17	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
18	
19	const sum = (numbers: number[]): number =>
20	  numbers.reduce((total, n) => total + n, 0);
21	
22	const applyFirstInsuranceSurcharge = (amount: number): number =>
23	  amount + amount * FIRST_INSURANCE_SURCHARGE_RATE;
24	
25	export const runScenario = (input: any): unknown => {
26	  const items: Item[] = input.steps[0].items;
27	  const itemsBase = sum(items.map(itemBasePremium));
28	  const premium = applyFirstInsuranceSurcharge(itemsBase) + PROCESSING_FEE;
29	  return quoteResult(Math.ceil(premium));
